// claim-office.spec.ts
import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: empty / fee
  it.todo("should return premium of 5 G for empty item list (just processing fee)");

  // Quote: single base items (with first-insurance +10% policy modifier and 5 G fee)
  it.todo("should quote a single Sword (base 100 G + 10% first insurance + 5 G fee)");
  it.todo("should quote a single Amulet (base 60 G + 10% first insurance + 5 G fee)");
  it.todo("should quote a single Staff (base 80 G + 10% first insurance + 5 G fee)");
  it.todo("should quote a single Potion (base 40 G + 10% first insurance + 5 G fee)");
  it.todo("should quote a single Rune component (base 25 G + 10% first insurance + 5 G fee)");
  it.todo("should quote a single Moonstone component (base 25 G + 10% first insurance + 5 G fee)");

  // Quote: multiple items summed
  it.todo("should sum premiums for two different items in a single quote");

  // Quote: block of 3 alike components
  it.todo("should apply block-of-3 special premium (60 G) for three alike runes instead of 75 G");
  it.todo("should apply block-of-3 special premium (60 G) for three alike moonstones instead of 75 G");

  // Item-specific surcharges
  it.todo("should apply +50% cursed surcharge on the item base premium");
  it.todo("should apply +30% high-enchantment surcharge for enchantment >= 5");
  it.todo("should stack cursed and high-enchantment surcharges on the same item base");

  // Policy-wide modifiers
  it.todo("should apply -20% loyalty discount for customers with >= 2 years");
  it.todo("should apply -15% follow-up discount for contracts after the first");

  // Rounding
  it.todo("should round premium UP to a whole G");

  // Claim: basic deductible
  it.todo("should subtract 100 G deductible per damaged item from a basic claim");

  // Claim: payout cap
  it.todo("should cap total payout at 2x the policy insurance sum");

  // Claim: high enchantment clause
  it.todo("should reimburse 50% of damage when item has enchantment >= 8 (then deductible)");

  // Claim: dragon material clause
  it.todo("should reimburse full damage when item is made of dragon material");

  // Claim: both clauses combined
  it.todo("should apply 50% rule first then deductible when both high-enchantment and dragon material apply");

  // Claim: rounding
  it.todo("should round payouts DOWN to a whole G");

  // CLI errors (basic validation)
  it.todo("should error on unknown item type in a quote");
  it.todo("should error on a claim damages array that does not match policy items");
  it.todo("should error on negative damage amount in a claim");
});
